export function getLanguageConfig(language: string) {
  return languages.find((item) => item.slug === language);
}

export function getDocMeta(language: string, slug: string) {
  return getLanguageConfig(language)?.pages.find((page) => page.slug === slug);
}

export function getFirstDocPath() {
  const language = languages[0];
  const page = language?.pages[0];

  if (!language || !page) {
    return "/";
  }

  return `/docs/${language.slug}/${page.slug}`;
}

export function getPreviousNext(language: string, slug: string) {
  const pages = getLanguageConfig(language)?.pages ?? [];
  const index = pages.findIndex((page) => page.slug === slug);

  return {
    previous: index > 0 ? pages[index - 1] : undefined,
    next: index >= 0 && index < pages.length - 1 ? pages[index + 1] : undefined
  };
}
